// Captured verbatim from the run transcript. This is what the runtime actually generated +
// executed — the real example that replaces the third-party repo scripts in the research doc.

export const meta = {
  name: 'engine-audit',
  description: 'Read-only bug + quality audit of RemoteAgents Engine files',
  phases: [
    { title: 'Review', detail: 'One reviewer per file, structured findings' },
    { title: 'Verify', detail: 'Skeptic per finding tries to refute' },
    { title: 'Synthesize', detail: 'Dedup and severity-rank survivors' },
  ],
}

const FILES = [
  'src/RemoteAgents/Engine/Flow.cs',
  'src/RemoteAgents/Engine/FlowContext.cs',
  'src/RemoteAgents/Engine/Operation.cs',
  'src/RemoteAgents/Engine/OperationArgs.cs',
  'src/RemoteAgents/Engine/FlowConfig.cs',
  'src/RemoteAgents/Engine/FlowDefinition.cs',
  'src/RemoteAgents/Engine/IFlowFactory.cs',
]

const FINDINGS_SCHEMA = {
  type: 'object',
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          line: { type: 'string' },
          category: { type: 'string', enum: ['bug', 'correctness', 'design', 'quality', 'contract'] },
          severity: { type: 'string', enum: ['critical', 'major', 'minor'] },
          title: { type: 'string' },
          description: { type: 'string' },
          evidence: { type: 'string' }
        },
        required: ['file', 'line', 'category', 'severity', 'title', 'description', 'evidence']
      }
    }
  },
  required: ['findings']
}

const VERDICT_SCHEMA = {
  type: 'object',
  properties: {
    refuted: { type: 'boolean' },
    refutation_reason: { type: 'string' },
    confirmed_title: { type: 'string' }
  },
  required: ['refuted', 'refutation_reason', 'confirmed_title']
}

const SYNTHESIS_SCHEMA = {
  type: 'object',
  properties: {
    report: { type: 'string' }
  },
  required: ['report']
}

phase('Review')
log('Fanning out one reviewer per file...')

const allReviews = await parallel(FILES.map(filePath => () =>
  agent(
    `You are a senior C# / .NET 10 code reviewer doing a STRICT READ-ONLY audit. Do NOT modify, create, or delete any files.

Read the file at path: ${filePath}

Look for:
- Bugs and correctness issues (null dereferences, race conditions, missing guards, wrong logic)
- Contract violations (e.g. null returns from non-nullable methods, missing throws, wrong invariants)
- Design issues that create real problems now (not hypothetical future issues)
- Quality issues that make code confusing or error-prone
- Violations of these project rules: warning-free build, nullable on, no dead code, make illegal states unrepresentable, YAGNI

For each finding include:
- The exact file path
- Line number or range (as a string like "42" or "42-55")
- Category: bug | correctness | design | quality | contract
- Severity: critical | major | minor
- A concise title (10 words max)
- A description of WHY this is a problem
- Direct evidence: quote the relevant code snippet

Return ONLY findings you are confident about. Do not report nitpicks or style issues unless they create real confusion or risk.`,
    { label: `review:${filePath.split('/').pop()}`, phase: 'Review', schema: FINDINGS_SCHEMA }
  )
))

const flatFindings = allReviews.filter(Boolean).flatMap(r => r.findings)
log(`Collected ${flatFindings.length} raw findings across ${FILES.length} files. Starting skeptic verification...`)

phase('Verify')

const verified = await pipeline(
  flatFindings,
  (finding, originalFinding, idx) => agent(
    `You are a skeptical C# code reviewer. Your job is to REFUTE the following finding if you can. Read the cited file carefully.

Finding to scrutinize:
- File: ${finding.file}
- Line(s): ${finding.line}
- Category: ${finding.category}
- Severity: ${finding.severity}
- Title: ${finding.title}
- Description: ${finding.description}
- Evidence quoted: ${finding.evidence}

Instructions:
1. Read the actual file at ${finding.file} using your Read tool.
2. Look at the cited line(s) and surrounding context.
3. Try hard to REFUTE the finding: is the evidence misquoted? Is there a guard elsewhere that prevents the bug? Does the design actually make sense given the context? Is the "issue" actually intentional and correct?
4. Only mark refuted=false (i.e., CONFIRM the finding) if you genuinely cannot refute it after trying.

Return your verdict.`,
    { label: `verify:${finding.file.split('/').pop()}:${idx}`, phase: 'Verify', schema: VERDICT_SCHEMA }
  ),
  (verdict, originalFinding) => {
    if (!verdict) return null
    return { ...originalFinding, verdict }
  }
)

const confirmed = verified.filter(Boolean).filter(f => f.verdict && !f.verdict.refuted)
const refuted = verified.filter(Boolean).filter(f => f.verdict && f.verdict.refuted)

log(`Verification complete: ${confirmed.length} confirmed, ${refuted.length} refuted. Synthesizing report...`)

phase('Synthesize')

const synthesisInput = confirmed.map((f, i) =>
  `[${i+1}] ${f.severity.toUpperCase()} | ${f.category} | ${f.file}:${f.line}\nTitle: ${f.title}\nDescription: ${f.description}\nEvidence: ${f.evidence}`
).join('\n\n')

const synthesis = await agent(
  `You are a technical lead synthesizing a code audit report. Here are ${confirmed.length} confirmed findings from a read-only audit of these files in a .NET 10 C# project:

Files audited:
${FILES.join('\n')}

Confirmed findings (survived skeptic review):
${synthesisInput || '(none)'}

Also note: ${refuted.length} findings were refuted and excluded.

Produce a final audit report in Markdown with:
1. A one-paragraph executive summary
2. A findings table with columns: # | Severity | Category | File:Line | Title
3. For each finding (grouped by severity: critical first, then major, then minor), a subsection with:
   - The file and line
   - What the problem is and why it matters
   - The relevant code evidence
4. A brief "What to fix first" prioritization at the end

Deduplicate any findings that are essentially the same issue. Severity order: critical > major > minor. Be concise — this is a technical report, not a tutorial.`,
  { label: 'synthesize', phase: 'Synthesize', schema: SYNTHESIS_SCHEMA }
)

return {
  summary: {
    filesAudited: FILES.length,
    rawFindings: flatFindings.length,
    refuted: refuted.length,
    confirmed: confirmed.length,
  },
  report: synthesis ? synthesis.report : '(synthesis failed)',
  confirmedFindings: confirmed,
}
